export default function VSL() {
  const audioRef = useRef(null);
  const rafRef = useRef(null);
  const [started, setStarted] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(null);
  const [progress, setProgress] = useState(0);
  const [timecode, setTimecode] = useState("0:00");
  const currentCueRef = useRef(-1);

  const formatTime = (s) => {
    const m = Math.floor(s / 60);
    const sec = Math.floor(s % 60).toString().padStart(2, "0");
    return `${m}:${sec}`;
  };

  const showCue = useCallback((index) => {
    setCurrentSlide(cues[index].slide);
  }, []);

  const tick = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) return;
    const t = audio.currentTime;
    const dur = audio.duration || 65.4;
    setProgress((t / dur) * 100);
    setTimecode(formatTime(t) + " / " + formatTime(dur));
    for (let i = 0; i < cues.length; i++) {
      if (t >= cues[i].t && i > currentCueRef.current) {
        currentCueRef.current = i;
        showCue(i);
      }
    }
    rafRef.current = requestAnimationFrame(tick);
  }, [showCue]);

  const startVideo = () => {
    setStarted(true);
    setTimeout(() => {
      audioRef.current?.play();
      setIsPlaying(true);
      rafRef.current = requestAnimationFrame(tick);
    }, 600);
  };

  const togglePlay = () => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying) {
      audio.pause();
      setIsPlaying(false);
      cancelAnimationFrame(rafRef.current);
    } else {
      audio.play();
      setIsPlaying(true);
      rafRef.current = requestAnimationFrame(tick);
    }
  };

  const restart = () => {
    const audio = audioRef.current;
    if (!audio) return;
    audio.currentTime = 0;
    currentCueRef.current = -1;
    setCurrentSlide(null);
    setProgress(0);
    if (!isPlaying) {
      audio.play();
      setIsPlaying(true);
      rafRef.current = requestAnimationFrame(tick);
    }
  };

  const seekTo = (e) => {
    const audio = audioRef.current;
    if (!audio) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const pct = (e.clientX - rect.left) / rect.width;
    audio.currentTime = pct * (audio.duration || 65.4);
    currentCueRef.current = -1;
    for (let i = cues.length - 1; i >= 0; i--) {
      if (audio.currentTime >= cues[i].t) {
        currentCueRef.current = i;
        showCue(i);
        break;
      }
    }
  };

  useEffect(() => {
    const audio = audioRef.current;
    const handleEnded = () => {
      setIsPlaying(false);
      cancelAnimationFrame(rafRef.current);
    };
    audio?.addEventListener("ended", handleEnded);
    return () => {
      audio?.removeEventListener("ended", handleEnded);
      cancelAnimationFrame(rafRef.current);
    };
  }, []);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Barlow:ital,wght@0,300;0,400;0,600;0,700;1,300&display=swap');
        .vsl-root {
          position: fixed; inset: 0;
          background: #05080f;
          overflow: hidden;
          font-family: 'Barlow', sans-serif;
        }
        .vsl-root * { box-sizing: border-box; margin: 0; padding: 0; }
        .vsl-grain {
          position: fixed; inset: 0; pointer-events: none; z-index: 100; opacity: 0.35;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.05'/%3E%3C/svg%3E");
        }
        .vsl-blob { position: fixed; border-radius: 50%; filter: blur(120px); pointer-events: none; }
        .vsl-blob-cyan { width:600px;height:600px;background:rgba(0,194,255,0.06);top:-100px;left:-100px; }
        .vsl-blob-gold { width:500px;height:500px;background:rgba(245,158,11,0.05);bottom:-100px;right:-100px; }
        .vsl-logo {
          position: fixed; top: 32px; left: 40px;
          font-family: 'Bebas Neue', sans-serif; font-size: 13px;
          letter-spacing: 3px; color: #4a5568; z-index: 50;
        }
        .vsl-logo span { color: #00c2ff; }
        .vsl-timecode {
          position: fixed; top: 32px; right: 40px;
          font-size: 11px; letter-spacing: 2px; color: #4a5568; z-index: 50;
        }
        .vsl-progress {
          position: fixed; bottom: 0; left: 0; height: 2px;
          background: linear-gradient(90deg, #00c2ff, #f59e0b);
          z-index: 100; transition: width 0.1s linear;
        }
        .vsl-stage {
          position: fixed; inset: 0; display: flex;
          align-items: center; justify-content: center;
        }
        .vsl-slide { width: 100%; max-width: 900px; padding: 0 60px; text-align: center; z-index: 10; }
        .slide-wrapper {
          opacity: 0; transform: translateY(30px);
          transition: opacity 0.6s cubic-bezier(0.16,1,0.3,1), transform 0.6s cubic-bezier(0.16,1,0.3,1);
        }
        .slide-wrapper.visible { opacity: 1; transform: translateY(0); }
        .text-huge { font-family:'Bebas Neue',sans-serif;font-size:clamp(56px,9vw,110px);line-height:0.95;color:#fff;letter-spacing:1px; }
        .text-large { font-family:'Bebas Neue',sans-serif;font-size:clamp(40px,6vw,72px);line-height:1.05;color:#fff;letter-spacing:1px; }
        .text-medium { font-family:'Barlow',sans-serif;font-size:clamp(20px,3vw,32px);font-weight:300;line-height:1.4;color:rgba(255,255,255,0.85); }
        .text-small { font-family:'Barlow',sans-serif;font-size:clamp(16px,2.2vw,24px);font-weight:300;line-height:1.6;color:rgba(255,255,255,0.65); }
        .label-text { font-family:'Barlow',sans-serif;font-size:13px;letter-spacing:3px;text-transform:uppercase; }
        .step-label { font-family:'Barlow',sans-serif;font-size:11px;font-weight:600;letter-spacing:4px;text-transform:uppercase;color:#00c2ff;margin-bottom:16px; }
        .cyan { color: #00c2ff; }
        .gold { color: #f59e0b; }
        .muted { color: #4a5568; }
        .bold { font-weight: 700; }
        .italic { font-style: italic; }
        .strikethrough { text-decoration: line-through; }
        .divider-line { width:40px;height:1px;background:#00c2ff;margin:12px auto 0; }
        .stats-row { display:flex;justify-content:center;gap:12px;flex-wrap:wrap; }
        .stat-block { display:inline-flex;flex-direction:column;align-items:center;padding:24px 48px;border:1px solid rgba(0,194,255,0.2);background:rgba(0,194,255,0.04);margin:12px; }
        .stat-number { font-family:'Bebas Neue',sans-serif;font-size:clamp(48px,7vw,80px);line-height:1; }
        .stat-label-sm { font-size:11px;letter-spacing:3px;text-transform:uppercase;color:#4a5568;margin-top:6px; }
        .brand-name { font-family:'Bebas Neue',sans-serif;font-size:clamp(14px,2vw,18px);letter-spacing:6px;color:#4a5568;margin-bottom:16px; }
        .cta-phone { font-family:'Bebas Neue',sans-serif;font-size:42px;color:#00c2ff;letter-spacing:2px; }
        .cta-url { font-size:14px;color:#4a5568;letter-spacing:3px;text-transform:uppercase;margin-top:8px; }
        .cta-audit { margin-top:28px;font-size:12px;letter-spacing:3px;text-transform:uppercase;color:#4a5568; }
        .vsl-controls {
          position:fixed;bottom:20px;left:50%;transform:translateX(-50%);
          display:flex;align-items:center;gap:16px;z-index:200;
        }
        .ctrl-btn {
          background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);
          color:#4a5568;font-family:'Barlow',sans-serif;font-size:11px;letter-spacing:2px;
          text-transform:uppercase;padding:8px 16px;cursor:pointer;transition:all 0.2s ease;
        }
        .ctrl-btn:hover { color:#00c2ff;border-color:#00c2ff; }
        .seekbar {
          width:200px;height:2px;background:rgba(255,255,255,0.1);
          cursor:pointer;position:relative;margin:0 8px;
        }
        .seekfill { height:100%;background:#00c2ff;pointer-events:none; }
        .vsl-start {
          position:fixed;inset:0;background:#05080f;
          display:flex;flex-direction:column;align-items:center;justify-content:center;
          z-index:500;gap:28px;transition:opacity 0.8s ease;
        }
        .vsl-start.hide { opacity:0;pointer-events:none; }
        .start-logo { font-family:'Bebas Neue',sans-serif;font-size:28px;letter-spacing:6px;color:#fff; }
        .start-logo span { color:#00c2ff; }
        .start-title { font-family:'Barlow',sans-serif;font-size:13px;font-weight:300;letter-spacing:5px;text-transform:uppercase;color:#4a5568; }
        .start-sub { font-size:11px;color:rgba(74,85,104,0.6);letter-spacing:2px;margin-top:-12px; }
        .play-btn {
          width:72px;height:72px;border-radius:50%;
          border:1px solid rgba(0,194,255,0.4);background:rgba(0,194,255,0.08);
          cursor:pointer;display:flex;align-items:center;justify-content:center;
          transition:all 0.3s ease;margin-top:8px;
        }
        .play-btn:hover { background:rgba(0,194,255,0.15);border-color:#00c2ff;transform:scale(1.05); }
        .play-btn svg { fill:#00c2ff;width:24px;height:24px;margin-left:4px; }
      `}</style>

      <div className="vsl-root">
        <div className="vsl-grain" />
        <div className="vsl-blob vsl-blob-cyan" />
        <div className="vsl-blob vsl-blob-gold" />

        {started && (
          <>
            <div className="vsl-logo"><span>PRIME</span> VISIBILITY</div>
            <div className="vsl-timecode">{timecode}</div>
          </>
        )}

        <div className="vsl-progress" style={{ width: progress + "%" }} />

        <div className="vsl-stage">
          <div className="vsl-slide">
            {currentSlide && <SlideContent id={currentSlide} visible={true} />}
          </div>
        </div>

        {started && (
          <div className="vsl-controls">
            <button className="ctrl-btn" onClick={togglePlay}>
              {isPlaying ? "⏸ PAUSE" : "▶ PLAY"}
            </button>
            <div className="seekbar" onClick={seekTo}>
              <div className="seekfill" style={{ width: progress + "%" }} />
            </div>
            <button className="ctrl-btn" onClick={restart}>↺ RESTART</button>
          </div>
        )}

        <div className={`vsl-start ${started ? "hide" : ""}`}>
          <div className="start-logo"><span>PRIME</span> VISIBILITY</div>
          <div className="start-title">What We Actually Do</div>
          <div className="start-sub">65 seconds · 7 services · 1 system</div>
          <div className="play-btn" onClick={startVideo}>
            <svg viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>
          </div>
        </div>

        <audio ref={audioRef} preload="auto">
          <source src={AUDIO_SRC} type="audio/mpeg" />
        </audio>
      </div>
    </>
  );
}
